#include<bits/stdc++.h>
using namespace std;
bool is_prime(int n){
    if(n<2)return 0;
    for(int i=2;i*i<=n;i++)
        if(n%i==0)return 0;
    return 1;
}
int main(){
    int a,b;
    cin>>a>>b;
    int ans=0;
    for(int i=a;i<=b;i++)ans+=is_prime(i);
    cout<<ans;
    return 0;
}
